<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Falling Sand Sandbox</title>
  <style>
    :root {
      --bg-color: #121212;
      --text-color: #e0e0e0;
      --accent-color: #bb86fc;
      --button-bg: #333;
      --button-hover: #444;
      --button-active: #555;
    }

    body {
      margin: 0;
      padding: 0;
      background-color: var(--bg-color);
      color: var(--text-color);
      font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
      display: flex;
      flex-direction: column;
      align-items: center;
      min-height: 100vh;
    }

    h1 {
      margin-top: 20px;
      font-weight: 300;
      letter-spacing: 1px;
    }

    .controls {
      display: flex;
      gap: 10px;
      margin: 20px 0;
      flex-wrap: wrap;
      justify-content: center;
    }

    button {
      background-color: var(--button-bg);
      color: white;
      border: none;
      padding: 10px 20px;
      font-size: 14px;
      border-radius: 4px;
      cursor: pointer;
      transition: background-color 0.2s, transform 0.1s;
      box-shadow: 0 2px 5px rgba(0,0,0,0.3);
    }

    button:hover {
      background-color: var(--button-hover);
    }

    button:active {
      background-color: var(--button-active);
      transform: translateY(1px);
    }

    button.active {
      background-color: var(--accent-color);
      color: #121212;
      font-weight: bold;
    }

    .canvas-container {
      position: relative;
      margin: 0 auto;
      box-shadow: 0 0 20px rgba(0,0,0,0.5);
      border-radius: 4px;
      overflow: hidden;
    }

    canvas#sand {
      display: block;
      cursor: crosshair;
      image-rendering: pixelated; /* Keep pixels sharp */
    }

    .instructions {
      margin-top: 15px;
      font-size: 0.9em;
      color: #aaa;
      text-align: center;
      max-width: 600px;
    }
  </style>
</head>
<body>
  <h1>Falling Sand Sandbox</h1>

  <div class="controls">
    <button id="mat-sand" class="active">Sand</button>
    <button id="mat-water">Water</button>
    <button id="mat-wall">Wall</button>
    <button id="mat-acid">Acid</button>
    <button id="mat-empty" class="eraser">Eraser</button>
  </div>

  <div class="controls">
    <button id="clear">Clear Canvas</button>
  </div>

  <div class="canvas-container">
    <canvas id="sand"></canvas>
  </div>

  <p class="instructions">
    Click and drag to paint. Sand falls, Water flows, Acid dissolves walls and sand.
  </p>

  <script>
    // Configuration
    const GRID_W = 120;
    const GRID_H = 100;
    const CELL_SIZE = 5; // Each cell is 5x5 pixels on screen

    // Material constants
    const EMPTY = 'empty';
    const SAND = 'sand';
    const WATER = 'water';
    const WALL = 'wall';
    const ACID = 'acid';

    // Grid state
    let grid = [];

    // Canvas setup
    const canvas = document.getElementById('sand');
    const ctx = canvas.getContext('2d', { alpha: false }); // Optimize for no transparency

    function initGrid() {
      grid = new Array(GRID_H).fill(null).map(() => new Array(GRID_W).fill(EMPTY));
    }

    function resizeCanvas() {
      canvas.width = GRID_W * CELL_SIZE;
      canvas.height = GRID_H * CELL_SIZE;
      canvas.style.width = `${GRID_W * CELL_SIZE}px`;
      canvas.style.height = `${GRID_H * CELL_SIZE}px`;
    }

    // Drawing functions
    function getColor(material) {
      switch (material) {
        case SAND:   return '#e6c229'; // Yellowish sand
        case WATER:  return '#3498db'; // Blue water
        case WALL:   return '#7f8c8d'; // Grey wall
        case ACID:   return '#76ff03'; // Bright green acid
        default:     return '#121212'; // Background color for empty
      }
    }

    function draw() {
      ctx.fillStyle = getColor(EMPTY);
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      for (let y = 0; y < GRID_H; y++) {
        for (let x = 0; x < GRID_W; x++) {
          const material = grid[y][x];
          if (material !== EMPTY) {
            ctx.fillStyle = getColor(material);
            ctx.fillRect(x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE);
          }
        }
      }
    }

    // Simulation logic
    function tick() {
      // Process from bottom to top to ensure particles move at most one cell per step
      for (let y = GRID_H - 2; y >= 0; y--) {
        // Randomize horizontal direction to avoid bias
        const leftFirst = Math.random() < 0.5;

        for (let x = 0; x < GRID_W; x++) {
          const material = grid[y][x];

          if (material === SAND) {
            // Try to fall down
            if (grid[y + 1][x] === EMPTY || grid[y + 1][x] === WATER || grid[y + 1][x] === ACID) {
              // Swap with water/acid, move into empty
              grid[y][x] = grid[y + 1][x];
              grid[y + 1][x] = SAND;
            } else if (grid[y + 1][x] !== WALL) {
              // Blocked below, try diagonal movement
              const dir = leftFirst ? -1 : 1; // Randomize direction first

              // Check both directions
              let moved = false;
              for (let d of [dir, -dir]) {
                if (x + d >= 0 && x + d < GRID_W) {
                  if (grid[y + 1][x + d] === EMPTY || grid[y + 1][x + d] === WATER || grid[y + 1][x + d] === ACID) {
                    grid[y][x] = grid[y + 1][x + d];
                    grid[y + 1][x + d] = SAND;
                    moved = true;
                    break;
                  }
                }
              }
            }
          } else if (material === WATER) {
            // Try to fall down
            if (grid[y + 1][x] === EMPTY) {
              grid[y + 1][x] = WATER;
              grid[y][x] = EMPTY;
            } else if (grid[y + 1][x] !== WALL && grid[y + 1][x] !== ACID) {
              // Blocked below, try diagonal movement
              const dir = leftFirst ? -1 : 1;

              let moved = false;
              for (let d of [dir, -dir]) {
                if (x + d >= 0 && x + d < GRID_W) {
                  if (grid[y + 1][x + d] === EMPTY) {
                    grid[y + 1][x + d] = WATER;
                    grid[y][x] = EMPTY;
                    moved = true;
                    break;
                  }
                }
              }

              // If still can't move down, try horizontal spreading
              if (!moved && (grid[y + 1][x] === WALL || grid[y + 1][x] === ACID)) {
                for (let d of [dir, -dir]) {
                  if (x + d >= 0 && x + d < GRID_W) {
                    if (grid[y][x + d] === EMPTY) {
                      grid[y][x + d] = WATER;
                      grid[y][x] = EMPTY;
                      break;
                    }
                  }
                }
              } else if (!moved) {
                // Try horizontal at same level
                for (let d of [dir, -dir]) {
                  if (x + d >= 0 && x + d < GRID_W) {
                    if (grid[y][x + d] === EMPTY) {
                      grid[y][x + d] = WATER;
                      grid[y][x] = EMPTY;
                      break;
                    }
                  }
                }
              }
            } else if (grid[y + 1][x] === ACID) {
              // Acid is below water, just swap
              grid[y + 1][x] = WATER;
              grid[y][x] = ACID;
            }
          } else if (material === ACID) {
            // Try to fall down
            if (grid[y + 1][x] === EMPTY || grid[y + 1][x] === WATER) {
              grid[y][x] = grid[y + 1][x];
              grid[y + 1][x] = ACID;
            } else if (grid[y + 1][x] !== WALL && grid[y + 1][x] !== SAND) {
              // Blocked below, try diagonal movement
              const dir = leftFirst ? -1 : 1;

              let moved = false;
              for (let d of [dir, -dir]) {
                if (x + d >= 0 && x + d < GRID_W) {
                  if (grid[y + 1][x + d] === EMPTY || grid[y + 1][x + d] === WATER) {
                    const target = grid[y + 1][x + d];
                    grid[y + 1][x + d] = ACID;
                    grid[y][x] = target;
                    moved = true;
                    break;
                  }
                }
              }

              // If still can't move down, try horizontal spreading
              if (!moved) {
                for (let d of [dir, -dir]) {
                  if (x + d >= 0 && x + d < GRID_W) {
                    if (grid[y][x + d] === EMPTY || grid[y][x + d] === WATER) {
                      const target = grid[y][x + d];
                      grid[y][x + d] = ACID;
                      grid[y][x] = target;
                      break;
                    }
                  }
                }
              }
            } else if (grid[y + 1][x] === WALL || grid[y + 1][x] === SAND) {
              // Acid dissolves wall or sand below
              grid[y + 1][x] = EMPTY; // Dissolve the target
              // Acid may also disappear or continue - let's make it have a chance to disappear
              if (Math.random() < 0.3) {
                grid[y][x] = EMPTY; // Acid gets used up in reaction
              }
            } else if (grid[y + 1][x] === ACID) {
              // Just swap with another acid
              grid[y + 1][x] = ACID;
              grid[y][x] = ACID;
            }

            // Check for dissolution beside at same level
            const dir = leftFirst ? -1 : 1;
            for (let d of [dir, -dir]) {
              if (x + d >= 0 && x + d < GRID_W) {
                if ((grid[y][x + d] === WALL || grid[y][x + d] === SAND) && Math.random() < 0.2) {
                  grid[y][x + d] = EMPTY; // Dissolve
                  if (Math.random() < 0.3) {
                    grid[y][x] = EMPTY; // Acid gets used up
                  }
                }
              }
            }
          }
        }
      }
    }

    function tickN(n) {
      for (let i = 0; i < n; i++) {
        tick();
      }
    }

    // Expose API on window
    window.sim = {
      w: GRID_W,
      h: GRID_H,

      tick(n) {
        if (typeof n !== 'number' || n < 1) {
          n = 1;
        }
        tickN(n);
        draw();
      },

      get(x, y) {
        if (x < 0 || x >= GRID_W || y < 0 || y >= GRID_H) {
          return EMPTY;
        }
        return grid[y][x];
      },

      set(x, y, material) {
        if (x < 0 || x >= GRID_W || y < 0 || y >= GRID_H) {
          return;
        }

        // Validate material
        const validMaterials = [EMPTY, SAND, WATER, WALL, ACID];
        if (!validMaterials.includes(material)) {
          return;
        }

        grid[y][x] = material;
      },

      clear() {
        initGrid();
        draw();
      }
    };

    // Initialize
    resizeCanvas();
    initGrid();
    draw();

    // Interaction handling
    let isDrawing = false;
    let currentMaterial = SAND;

    function getMousePos(canvas, evt) {
      const rect = canvas.getBoundingClientRect();
      const scaleX = GRID_W / rect.width;
      const scaleY = GRID_H / rect.height;

      return {
        x: Math.floor((evt.clientX - rect.left) * scaleX),
        y: Math.floor((evt.clientY - rect.top) * scaleY)
      };
    }

    function paint(e) {
      if (!isDrawing) return;

      const pos = getMousePos(canvas, e);
      const x = pos.x;
      const y = pos.y;

      // Add some brush size (3x3 area)
      for (let dy = -1; dy <= 1; dy++) {
        for (let dx = -1; dx <= 1; dx++) {
          if (Math.random() > 0.2) { // Randomize slightly for natural look
            const px = x + dx;
            const py = y + dy;

            if (px >= 0 && px < GRID_W && py >= 0 && py < GRID_H) {
              window.sim.set(px, py, currentMaterial);
            }
          }
        }
      }

      draw();
    }

    canvas.addEventListener('mousedown', (e) => {
      isDrawing = true;
      paint(e);
    });

    canvas.addEventListener('mousemove', paint);

    canvas.addEventListener('mouseup', () => {
      isDrawing = false;
    });

    canvas.addEventListener('mouseleave', () => {
      isDrawing = false;
    });

    // Button handling
    const buttons = document.querySelectorAll('.controls button');

    function setActiveButton(activeBtn) {
      buttons.forEach(btn => btn.classList.remove('active'));
      activeBtn.classList.add('active');
    }

    document.getElementById('mat-sand').addEventListener('click', () => {
      currentMaterial = SAND;
      setActiveButton(this);
    });

    document.getElementById('mat-water').addEventListener('click', () => {
      currentMaterial = WATER;
      setActiveButton(this);
    });

    document.getElementById('mat-wall').addEventListener('click', () => {
      currentMaterial = WALL;
      setActiveButton(this);
    });

    document.getElementById('mat-acid').addEventListener('click', () => {
      currentMaterial = ACID;
      setActiveButton(this);
    });

    document.getElementById('mat-empty').addEventListener('click', () => {
      currentMaterial = EMPTY;
      setActiveButton(this);
    });

    document.getElementById('clear').addEventListener('click', () => {
      window.sim.clear();
    });

    // Animation loop
    let lastTime = 0;
    const FPS = 30;

    function animate(timestamp) {
      if (!lastTime) lastTime = timestamp;

      const elapsed = timestamp - lastTime;

      if (elapsed > 1000 / FPS) {
        window.sim.tick(1);
        lastTime = timestamp;
      }

      requestAnimationFrame(animate);
    }

    // Start animation
    requestAnimationFrame(animate);

    // Initial draw to show something before first tick
    draw();
  </script>
</body>
</html>
